// Extraer el buildId actual de Next.js (cambia en cada despliegue de Flexicar).
// Se usará para la vía JSON /_next/data/{buildId}/...
const html = typeof $input.item.json === 'string' ? $input.item.json
  : String($input.item.json.data || $input.item.json.body || '');
const m = html.match(/"buildId":"([^"]+)"/);
const buildId = m ? m[1] : '';
console.log('[flexicar-scraper] buildId=' + buildId);
return [{ json: { buildId: buildId } }];

// Flexicar rompió la paginación (?page=N da 403 / la ignora). Faceteo por categoría:
// cada /{slug}/segunda-mano.json (vía _next/data) devuelve 12 coches destacados de esa
// porción. Usando ~92 slices (marcas + carrocería + combustible + plazas + transmisión)
// se descubren ~1.100 URLs/vuelta (con solapamiento) → capta altas nuevas y refresca activos.
const buildId = $input.item.json.buildId || '';
const slugs = [
  "peugeot","audi","bmw","mercedes-benz","citroen","volkswagen","ford","opel","seat","renault",
  "toyota","kia","fiat","nissan","hyundai","skoda","cupra","dacia","mini","volvo","mazda","mg",
  "jeep","ds","land-rover","lexus","suzuki","honda","alfa-romeo","mitsubishi","porsche","jaguar",
  "smart","tesla","abarth","subaru","maserati","ssangyong","iveco","chevrolet","lancia","infiniti",
  "dfsk","byd","ferrari","bentley","dodge","chrysler","polestar","saab","cadillac","isuzu","hummer",
  "maxus","omoda","jaecoo","leapmotor","ebro","evo","dr-automobiles","mahindra","tata","aiways",
  "seres","skywell","swm","xev","xiaomi","zhidou","aston-martin",
  "carroceria-suv-4x4","carroceria-turismo","carroceria-compacto","carroceria-familiar",
  "carroceria-monovolumen","carroceria-furgoneta","carroceria-cabrio","carroceria-deportivo",
  "carroceria-pick-up","combustible-diesel","combustible-gasolina","combustible-electrico",
  "combustible-hibrido-no-enchufable","combustible-hibrido-enchufable","combustible-glp",
  "transmision-automatica","transmision-manual","plazas-7","plazas-9","plazas-6","plazas-8","plazas-10"
];
const out = [];
for (const s of slugs) {
  out.push({ json: { url: 'https://www.flexicar.es/_next/data/' + buildId + '/' + s + '/segunda-mano.json' } });
}
return out;

// Digiere lo que venga: JSON del endpoint _next/data O HTML del listado.
const raw = $input.item.json;
const body = typeof raw === 'string' ? raw : String(raw.data || raw.body || '');

let pp = null;
// 1) Intentar como JSON (vía rápida /_next/data)
try {
  const j = JSON.parse(body);
  pp = j.pageProps || (j.props && j.props.pageProps) || null;
} catch (e) {
  // 2) Es HTML (vía respaldo) → extraer __NEXT_DATA__
  const m = body.match(/<script id="__NEXT_DATA__"[^>]*>([\s\S]*?)<\/script>/);
  if (m) {
    try { pp = JSON.parse(m[1]).props.pageProps; } catch (_) {}
  }
}

const vehicles = (pp && pp.initialVehicles) || [];
if (!vehicles.length) {
  return [{ json: { sql: null, count: 0 } }];
}

function normalizeFuel(raw) {
  const s = String(raw || '').toLowerCase();
  if (s.indexOf('diesel') !== -1 || s.indexOf('diésel') !== -1) return 'Diesel';
  if (s.indexOf('electr') !== -1) return 'Eléctrico';
  const enchufable = (s.indexOf('enchufable') !== -1 || s.indexOf('plug') !== -1) && s.indexOf('no enchufable') === -1;
  if (s.indexOf('hibrido') !== -1 || s.indexOf('híbrido') !== -1 || s.indexOf('hybrid') !== -1 || s.indexOf('enchufable') !== -1) return enchufable ? 'Híbrido enchufable' : 'Híbrido';
  if (s.indexOf('gasolina') !== -1 || s.indexOf('petrol') !== -1) return 'Gasolina';
  if (s.indexOf('glp') !== -1 || s.indexOf('gnc') !== -1 || s.indexOf('gas') !== -1) return 'Gas';
  return raw || '';
}

function normalizeGear(raw) {
  const s = String(raw || '').toLowerCase();
  if (s.indexOf('autom') !== -1) return 'Automatica';
  if (s.indexOf('manual') !== -1) return 'Manual';
  return raw || '';
}

function normalizeLabel(raw) {
  var s = String(raw || '').toLowerCase().trim();
  if (!s) return '';
  if (s === 'zero' || s === 'cero' || s === '0' || s.indexOf('0 emis') !== -1) return '0 Emisiones';
  if (s === 'eco' || s === 'e') return 'ECO';
  if (s === 'c' || s === 'green') return 'C';
  if (s === 'b' || s === 'yellow') return 'B';
  return String(raw).toUpperCase();
}

function esc(v) {
  if (v === null || v === undefined) return 'NULL';
  if (typeof v === 'number') return isNaN(v) ? 'NULL' : String(v);
  return "'" + String(v).replace(/'/g, "''") + "'";
}

const rows = [];
for (const v of vehicles) {
  const id = String(v.id);
  const url = v.slug ? 'https://www.flexicar.es/coches-ocasion/' + v.slug + '/' : '';
  const brand = v.brand || '';
  const model = v.model || '';
  const version = v.version || '';
  const title = (brand + ' ' + model + ' ' + version).replace(/\s+/g, ' ').trim();
  const kwMatch = version.match(/(\d+)\s*kW/i);
  const cvMatch = version.match(/\((\d+)\s*CV\)/i);
  const powerKw = kwMatch ? parseInt(kwMatch[1], 10) : null;
  const powerCv = cvMatch ? parseInt(cvMatch[1], 10) : (kwMatch ? Math.round(parseInt(kwMatch[1], 10) * 1.3596) : null);
  const year = (v.year != null) ? String(v.year) : 'NULL';
  const mileage = (v.km != null) ? String(v.km) : 'NULL';
  const fuel = normalizeFuel(v.fuel);
  const transmission = normalizeGear(v.transmission);
  const contadoRaw = (v.cashPrice != null) ? v.cashPrice : v.price;
  const price = (contadoRaw != null) ? String(contadoRaw) : 'NULL';
  const financePrice = (v.price != null) ? String(v.price) : 'NULL';
  const monthlyPrice = (v.quotaPrice != null) ? String(v.quotaPrice) : 'NULL';
  const color = v.color || '';
  const ecoSticker = normalizeLabel(v.ecoSticker);
  const imageUrl = v.image || '';
  const imagesArr = (Array.isArray(v.images) ? v.images : (imageUrl ? [imageUrl] : [])).filter(function(u){ return u && u.indexOf('/generic/') === -1 && u.indexOf('dealer_network') === -1; }).slice(0, 10);
  const imagesJson = JSON.stringify(imagesArr).replace(/'/g, "''");
  const dealerName = 'Flexicar';
  const dealershipRaw = v.carDealership || '';
  const city = dealershipRaw.split(' - ')[0].trim();
  const location = city || 'Toda España';

  const row = '(' +
    esc(id) + ', ' + esc(url) + ', ' + esc(title) + ', ' + esc(brand) + ', ' + esc(model) + ', ' +
    esc(version) + ', ' + year + ', ' + mileage + ', ' +
    price + ', ' + financePrice + ', ' + monthlyPrice + ', ' +
    esc(fuel) + ', ' + esc(transmission) + ', ' + esc(color) + ', ' +
    esc(imageUrl) + ", '" + imagesJson + "', " +
    esc(ecoSticker) + ', ' +
    esc(dealerName) + ', ' + esc(city) + ', ' + esc(location) + ', ' +
    "'flexicar', 'profesional', 'compra', 12, " + (powerCv !== null ? String(powerCv) : 'NULL') + ', ' + (powerKw !== null ? String(powerKw) : 'NULL') + ", NOW(), NOW(), NOW()" +
  ')';
  rows.push(row);
}

const cols = 'id, url, title, brand, model, version, year, mileage, price, finance_price, monthly_price, fuel, transmission, color, image_url, images, environmental_label, dealer_name, city, location, portal, seller_type, listing_type, warranty_months, power_cv, power_kw, first_seen_at, scraped_at, last_seen_at';

const onConflict = 'ON CONFLICT (id) DO UPDATE SET ' +
  'url = EXCLUDED.url, ' +
  'title = EXCLUDED.title, ' +
  'price = EXCLUDED.price, ' +
  'finance_price = EXCLUDED.finance_price, ' +
  'monthly_price = EXCLUDED.monthly_price, ' +
  'mileage = EXCLUDED.mileage, ' +
  "image_url = COALESCE(NULLIF(moveadvisor_market_offers.image_url, ''), EXCLUDED.image_url), " +
  "images = COALESCE(NULLIF(moveadvisor_market_offers.images, ''), EXCLUDED.images), " +
  "color = COALESCE(NULLIF(moveadvisor_market_offers.color, ''), EXCLUDED.color), " +
  "environmental_label = COALESCE(NULLIF(moveadvisor_market_offers.environmental_label, ''), EXCLUDED.environmental_label), " +
  'power_cv = COALESCE(EXCLUDED.power_cv, moveadvisor_market_offers.power_cv), ' +
  'power_kw = COALESCE(EXCLUDED.power_kw, moveadvisor_market_offers.power_kw), ' +
  '' +
  'last_seen_at = NOW(), ' +
  'updated_at = NOW()';

const sql = 'INSERT INTO moveadvisor_market_offers (' + cols + ') VALUES ' + rows.join(', ') + ' ' + onConflict;

return [{ json: { sql: sql, count: vehicles.length } }];
